    const d = document.createElement('div')
    d.style.cssText = 'position:fixed;inset:0;z-index:9999;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:8vw;background:linear-gradient(#bcd6e6,#e8dcc2);color:#3b3024;font-family:system-ui,sans-serif;line-height:1.9;'
