    const arm = new THREE.Mesh(new THREE.CylinderGeometry(0.07, 0.07, 1.6, 6), toon(0x6a7a86)); arm.rotation.z = Math.PI / 2; arm.position.set(0.7, 2.5, 0); tg.add(arm)
