    const lbulb = new THREE.Mesh(new THREE.SphereGeometry(0.14, 10, 10), new THREE.MeshBasicMaterial({ color: 0xffe2a6, fog: false, transparent: true, opacity: 0 })); lbulb.position.set(cx + 6.5, fy + 4.25, cz - 6); scene.add(lbulb)
