      const body = new THREE.Mesh(new THREE.BoxGeometry(W, H, D), kuraW); body.position.y = H / 2; g.add(body)
      const base = new THREE.Mesh(new THREE.BoxGeometry(W + 0.2, 1.2, D + 0.2), toon(0x6a6e74)); base.position.y = 0.6; g.add(base)
