// ── 番犬（犬小屋のそばで しっぽを振り、たまに吠える垂れ耳の犬）＝住宅街の生活感（鳴き声だけだったのに姿を。B4②・2026-06-26）。繋がれた番犬＝道/水に迷い込まない ──
function makeDog(furCol, creamCol) {
  const g = new THREE.Group()
  const fur = toon(furCol || 0xc89b62), cream = toon(creamCol || 0xf0e6d2)
  // 胴＝横向きカプセル＋腰のふくらみ＋首＝ずんぐりした一個の球(塊感)をやめ、犬らしい流れる輪郭に（ユーザー要望2026-06-28）
  const body = new THREE.Mesh(new THREE.CapsuleGeometry(0.18, 0.46, 6, 12), fur); body.rotation.z = Math.PI / 2; body.position.set(-0.02, 0.52, 0); g.add(body); g.userData.body = body
  const hip = new THREE.Mesh(new THREE.SphereGeometry(0.205, 12, 10), fur); hip.scale.set(1.0, 1.06, 1.02); hip.position.set(-0.36, 0.52, 0); g.add(hip) // 腰（後ろ脚の付け根）
  const chest = new THREE.Mesh(new THREE.SphereGeometry(0.17, 10, 8), cream); chest.scale.set(0.82, 1.05, 0.86); chest.position.set(0.4, 0.43, 0); g.add(chest)
  const neck = new THREE.Mesh(new THREE.CylinderGeometry(0.125, 0.16, 0.24, 8), fur); neck.position.set(0.42, 0.64, 0); neck.rotation.z = -0.6; g.add(neck) // 首（頭へ斜めに）
  const head = new THREE.Group(); head.position.set(0.58, 0.8, 0); g.add(head); g.userData.head = head // 頭はグループ＝吠える時に上を向く
  head.add(new THREE.Mesh(new THREE.SphereGeometry(0.22, 14, 12), fur))
  { const sn = new THREE.Mesh(new THREE.SphereGeometry(0.135, 12, 10), cream); sn.scale.set(1.3, 0.82, 0.85); sn.position.set(0.24, -0.05, 0); head.add(sn) } // 鼻面（前へ）
  for (const ez of [-0.17, 0.17]) { const ear = new THREE.Mesh(new THREE.SphereGeometry(0.11, 8, 8), fur); ear.scale.set(0.5, 1.2, 0.85); ear.position.set(-0.04, 0.03, ez); ear.rotation.x = ez > 0 ? 0.22 : -0.22; head.add(ear) } // 垂れ耳
  const tail = new THREE.Mesh(new THREE.CylinderGeometry(0.06, 0.032, 0.5, 6), fur); tail.geometry.translate(0, 0.25, 0); tail.position.set(-0.5, 0.6, 0); tail.rotation.z = 1.0; g.add(tail); g.userData.tail = tail // 上向きのしっぽ（根元支点で振る）
  const dlegs = [] // 4本の脚を股ピボット化＝歩く時に交互に振る（4足歩行・ユーザー要望2026-06-28）。並び＝前左/前右/後左/後右
  for (const [lx, lz, back] of [[0.34, 0.18, 0], [0.34, -0.18, 0], [-0.34, 0.18, 1], [-0.34, -0.18, 1]]) {
    const hip = new THREE.Group(); hip.position.set(lx, 0.52, lz); g.add(hip) // 脚の付け根（ここを支点に前後へ振る）
    if (back) { const thigh = new THREE.Mesh(new THREE.SphereGeometry(0.1, 8, 8), fur); thigh.scale.set(0.86, 1.12, 0.86); thigh.position.set(0.03, -0.18, 0); hip.add(thigh) } // 後ろ脚の腿のふくらみ
    const leg = new THREE.Mesh(new THREE.CylinderGeometry(0.06, 0.05, 0.52, 6), fur); leg.position.y = -0.26; hip.add(leg) // 付け根からぶら下がる細め・少し長めの脚
    const paw = new THREE.Mesh(new THREE.SphereGeometry(0.072, 8, 6), cream); paw.scale.set(1, 0.72, 1.25); paw.position.set(0.02, -0.49, 0); hip.add(paw)
    dlegs.push(hip)
  }
  g.userData.legs = dlegs
  { const col = new THREE.Mesh(new THREE.TorusGeometry(0.155, 0.038, 6, 14), toon(0xb5462f)); col.position.set(0.46, 0.68, 0); col.rotation.y = Math.PI / 2; col.scale.set(1, 0.85, 1); g.add(col) } // 赤い首輪（首のあたり）
  g.traverse((o) => { if (o.isMesh) o.castShadow = false }) // 動く犬も残像防止
  outlineObj(g, 0.022); addContactShadow(g, 0.78)
  // 顔（輪郭線の後・フチ無し）：目・鼻
  for (const ez of [-0.1, 0.1]) { const e = new THREE.Mesh(new THREE.SphereGeometry(0.044, 10, 8), new THREE.MeshBasicMaterial({ color: 0x2a2018 })); e.position.set(0.14, 0.07, ez); head.add(e); const hi = new THREE.Mesh(new THREE.SphereGeometry(0.016, 8, 8), new THREE.MeshBasicMaterial({ color: 0xffffff })); hi.position.set(0.172, 0.09, ez + (ez > 0 ? 0.01 : -0.01)); head.add(hi) }
  { const nose = new THREE.Mesh(new THREE.SphereGeometry(0.048, 8, 6), new THREE.MeshBasicMaterial({ color: 0x2a2018 })); nose.position.set(0.39, -0.02, 0); head.add(nose) }
  scene.add(g)
  return g
}
const makeKennel = (x, z, rot) => { const g = new THREE.Group(), wood = toon(0xa9885c), wood2 = toon(0x8f6f48)
  g.add(new THREE.Mesh(new THREE.BoxGeometry(1.0, 0.72, 1.0), wood)).position.y = 0.36
  { const r = new THREE.Mesh(new THREE.ConeGeometry(0.86, 0.5, 4), wood2); r.position.y = 0.97; r.rotation.y = Math.PI / 4; g.add(r) } // 寄棟っぽい屋根
  { const h = new THREE.Mesh(new THREE.CircleGeometry(0.28, 14), toon(0x241f18)); h.position.set(0, 0.34, 0.501); g.add(h) } // 入口の穴
  g.traverse((o) => { if (o.isMesh) o.castShadow = true }); mergedOutline(g, 0.02); placeProp(g, x, z, rot, 0, 0.7) }
const dogs = []
// 住宅街の歩く所ぞいに番犬＋犬小屋（毛色ちがい）。各=｛犬, 犬小屋, 向き｝。位置は道/水を避けた家のそば
for (const [dx, dz, rot, fc, cc] of [[2952, -64, 2.2, 0xc89b62, 0xf0e6d2], [3086, -150, -1.0, 0x6b5640, 0xe8ddc8]]) {
  const d = makeDog(fc, cc); const gy = heightAt(dx, dz); d.position.set(dx, gy, dz); d.rotation.y = rot
  makeKennel(dx - Math.cos(rot) * 1.2, dz - Math.sin(rot) * 1.2, rot + Math.PI) // 犬小屋は犬の後ろ
  Object.assign(d.userData, { bark: 4 + Math.random() * 8, barkT: 0, ph: Math.random() * 6.28, hx: dx, hz: dz, ry0: rot, paceProg: 0, paceDir: 1, pacing: false, paceTimer: 4 + Math.random() * 6, gphase: Math.random() * 6.28, dmoving: false }); dogs.push(d) // pace=繋がれた犬が前後にうろうろ歩く（歩行モーション・2026-06-28）
}

// ── 主人公（丸っこく立体的な少年・麦わら帽子。あどけない頭でっかちの体つき）──
// ※特定作品のキャラ・顔の模倣はしない。素朴で可愛い普遍的なトゥーン顔。
// ── キャラのプロポーション（小学生＝5〜6頭身・すっきり。数値だけ後から微調整できる。主人公も村人も共有）──
const PROP = {
  hipY: 0.80, thigh: 0.37, shin: 0.35, legR: 0.057,            // 脚：長くまっすぐ・細い（重心を上げる）
  shoulderY: 1.30, upperArm: 0.30, fore: 0.29, armR: 0.05,     // 腕：長くまっすぐ・細い
  waistY: 0.84, chestY: 1.18, torsoTopR: 0.132, torsoBotR: 0.112, // 胴：縦長・すっきり（ずんぐり解消）
  neckY: 1.37, headY: 1.575, headR: 0.145, headSX: 1.05, headSY: 1.12, headSZ: 1.03, // 頭：小さめ＝頭身を上げる
  eyeR: 0.0315, eyeX: 0.057, eyeY: 0.012, eyeZ: 0.12, irisRatio: 0.6, // 目：小さめで繊細・素朴（ユーザー要望2026-06-26「もっと控えめに」＝ほぼ元の小さめへ戻す。黒目を小さく＝白目とのバランスを自然に）
  hair: 0x6e4d34, hairTop: 0.37, hairExtent: 0.32, hairY: 0.0, hairTilt: -0.05, // 髪：色・帯の開始(髪の上端をつばより下に＝つばのひさしが隠す＝クラウンから突き出ない)・帯の長さ・高さ・ごく控えめな後傾
  hatBrim: 0.27, hatBrimY: 0.096, hatCap: 0.15, hatCapY: 0.096, hatCapExtent: 0.6, // 麦わら帽子：つば半径/高さ・クラウン半径/中心高さ/平たさ(y縮尺。平たいドームを髪の上に乗せる＝皿/くり抜きを回避)。つばを少し上げ前髪の居場所を作る
}
function limbCap(r, len, mat) { return new THREE.Mesh(new THREE.CapsuleGeometry(r, Math.max(0.012, len - r * 2), 8, 14), mat) } // まっすぐ細い手足用
const CHAR_SHOULDER_GEO = new THREE.SphereGeometry(PROP.torsoTopR + 0.012, 10, 8) // 簡易figure(通行人/踊り手/見物客)の肩＝首の付け根を隠して「首が異様に長い」を解消（2026-06-28・ユーザー指摘）。1個を共有して描画予算を節約
const NET_REST = -0.85 // 肩にかつぐ虫取り網の傾き（後ろへ寝かせる量）。0=直立 / 大きいほど後ろへ寝る。虫採り時はここから前へ振る。肩にちゃんと乗る角度に（浮き解消）
