    const knee = new THREE.Group(); knee.position.y = -P.thigh; hip.add(knee)
    const kneeCap = new THREE.Mesh(new THREE.SphereGeometry(P.legR * 0.96, 10, 8), skin); knee.add(kneeCap)   // 膝の継ぎ目（同径＝コブを作らない）
