  for (let rr = 3; rr <= maxR; rr += 3) for (let a = 0; a < 6.2832; a += 0.42) { const ex = x + Math.cos(a) * rr, ez = z + Math.sin(a) * rr; if (npcSpotOk(ex, ez, clearR)) return { x: ex, z: ez } } // 近くから螺旋状に開けた地面を探す
