    if (found) { const dy = pr.g.position.y - ground(pr.x, pr.z); pr.g.position.set(found.x, ground(found.x, found.z) + dy, found.z); pr.x = found.x; pr.z = found.z; moved++ } // y方向の据え付けオフセットは保つ
