    for (let rr = 1.5; rr <= 12 && !found; rr += 1) for (let a = 0; a < 6.2832; a += 0.4) { const ex = p.position.x + Math.cos(a) * rr, ez = p.position.z + Math.sin(a) * rr; if (!deepInBuilding(ex, ez) && !npcInWater(ex, ez) && !onYatoRoadCore(ex, ez)) { found = { x: ex, z: ez }; break } }
    if (found) { const dy = p.position.y - heightAtYato(p.position.x, p.position.z); p.position.set(found.x, heightAtYato(found.x, found.z) + dy, found.z); moved++ }
