    if (i === 0) r *= 1.12 // 底のコブは広め＝平らな底
    const jx = (Math.random() - 0.5) * baseW * hSpread + lean * ty * H // 横の散らし（綿雲は大きく＝横にもくもく／塔は控えめ）＋ローブを互い違いに
    const jz = (Math.random() - 0.5) * baseW * hSpread * 0.8
