  const hp = ctx.createBiquadFilter(); hp.type = 'highpass'; hp.frequency.value = 82; hp.Q.value = 0.7 // 可聴下のゴロつき/低周波ノイズを除く（スマホ/イヤホンで濁らない・温かみは残す控えめ設定）
