    L.x += L.vx * dt; L.z += L.vz * dt
    if ((L.x - L.cx) * (L.x - L.cx) + (L.z - L.cz) * (L.z - L.cz) > L.rad * L.rad) { L.vx = -L.vx; L.vz = -L.vz; L.x += L.vx * dt * 3; L.z += L.vz * dt * 3 } // 池の縁でゆっくり向きを返す
    const by = L.y + Math.sin(t * 0.8 + L.ph) * 0.04 // ゆらゆら
