      const tr = u.paceDir > 0 ? u.ry0 : u.ry0 + Math.PI; let da = tr - dg.rotation.y; while (da > Math.PI) da -= 6.2832; while (da < -Math.PI) da += 6.2832; dg.rotation.y += da * Math.min(1, dt * 6) // 進む向きへ（戻る時は反転）＝後ずさりでなく向きを変えて歩く
